import{_ as d,o as r,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - 財務分析專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260424/F05_應收帳款品質與收款天數.md","filePath":"審計報告庫/財務審計/6261_久元/20260424/F05_應收帳款品質與收款天數.md"}'),o={name:"審計報告庫/財務審計/6261_久元/20260424/F05_應收帳款品質與收款天數.md"};function e(i,t,n,h,s,Q){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="f05-應收帳款品質與收款天數-財務分析專家審計報告" tabindex="-1">F05: 應收帳款品質與收款天數 - 財務分析專家審計報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-財務分析專家審計報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - 財務分析專家審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>應收帳款（AR）的規模與週轉天數（DSO）變動為何？是否存在客戶拖欠或虛增營收風險？透過測算應收帳款週轉天數與對比營收成長率，識別是否存在「塞貨」或「放寬信用額度衝業績」的激進行為。</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至2025年Q4最新公開數據，久元（6261）應收帳款從FY23的8.39億元攀升至FY25的13.38億元，年增+59.5%。DSO從FY23的121天惡化至FY24的96天（改善），但FY25又回升至98天。關鍵警訊：應收帳款佔營收比重從FY23的29.3%大幅上升至FY25的42.5%，顯示收款效率正在惡化。雖然DSO尚未突破100天大關，但「AR成長速度持續快於營收成長速度」的趨勢已確認。若此趨勢延續至FY26，DSO可能突破110天，屆時將觸發「放帳衝業績」的警訊。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>評級：B（持平，略偏警訊）</strong></p><table tabindex="0"><thead><tr><th>年度</th><th>期末應收帳款(億元)</th><th>全年營收(億元)</th><th>AR/營收比</th><th>DSO(天)</th></tr></thead><tbody><tr><td>FY23 (112年)</td><td>8.39</td><td>261.70</td><td>3.2%</td><td>121.0</td></tr><tr><td>FY24 (113年)</td><td>9.79</td><td>303.11</td><td>3.2%</td><td>95.6</td></tr><tr><td>FY25 (114年)</td><td>13.38</td><td>315.17</td><td>4.2%</td><td>98.4</td></tr></tbody></table><blockquote><p>註：FY23為會計年度（6月結算），FY24/FY25為會計年度（3月結算）。DSO以季平均應收帳款 / (全年營收/365) 計算。</p></blockquote><p><strong>季度視角（更精確的趨勢判讀）：</strong></p><table tabindex="0"><thead><tr><th>季度</th><th>應收帳款(百萬元)</th><th>DSO(天)</th><th>AR QoQ變動</th><th>營收 QoQ變動</th></tr></thead><tbody><tr><td>23Q1 (112Q2)</td><td>839.3</td><td>—</td><td>—</td><td>—</td></tr><tr><td>23Q2 (112Q3)</td><td>939.8</td><td>102.7</td><td>+12.0%</td><td>-5.1%</td></tr><tr><td>23Q3 (112Q4)</td><td>1,071.9</td><td>82.1</td><td>+14.1%</td><td>+42.7%</td></tr><tr><td>24Q1 (113Q1)</td><td>1,066.3</td><td>102.4</td><td>-0.5%</td><td>-20.3%</td></tr><tr><td>24Q2 (113Q2)</td><td>1,128.9</td><td>89.0</td><td>+5.9%</td><td>+21.8%</td></tr><tr><td>24Q3 (113Q3)</td><td>981.5</td><td>91.7</td><td>-13.1%</td><td>-15.6%</td></tr><tr><td>24Q4 (113Q4)</td><td>979.3</td><td>95.2</td><td>-0.2%</td><td>-3.9%</td></tr><tr><td>25Q1 (114Q1)</td><td>993.1</td><td>89.9</td><td>+1.4%</td><td>+7.4%</td></tr><tr><td>25Q2 (114Q2)</td><td>1,008.0</td><td>94.9</td><td>+1.5%</td><td>-3.9%</td></tr><tr><td>25Q3 (114Q3)</td><td>1,181.8</td><td>100.5</td><td>+17.2%</td><td>+10.7%</td></tr><tr><td>25Q4 (114Q4)</td><td>1,338.2</td><td>101.8</td><td>+13.2%</td><td>+11.8%</td></tr></tbody></table><p><strong>DSO趨勢診斷：</strong> FY25Q4的DSO達101.8天，連續兩季突破100天大關。這意味著久元平均每筆銷售需要超過3.3個月才能收回現金。對於半導體測試設備業而言，90-100天為合理區間，超過100天即進入警戒區。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、dso趨勢-從改善到惡化的結構性轉變" tabindex="-1">一、DSO趨勢：從改善到惡化的結構性轉變 <a class="header-anchor" href="#一、dso趨勢-從改善到惡化的結構性轉變" aria-label="Permalink to &quot;一、DSO趨勢：從改善到惡化的結構性轉變&quot;">​</a></h3><p><strong>FY23→FY24：DSO改善期（121天→96天）</strong></p><ul><li>FY23的DSO高達121天，反映當時應收帳款管理效率較低</li><li>FY24DSO降至96天，改善25天（-20.7%），顯示收款效率顯著提升</li><li>可能原因：公司加強催收、客戶結構改善、或營收快速成長稀釋AR佔比</li></ul><p><strong>FY24→FY25：DSO惡化期（96天→98天）</strong></p><ul><li>FY24全年DSO 95.6天，FY25回升至98.4天</li><li>關鍵轉折點在FY25Q3-Q4：DSO從89.9天急升至101.8天</li><li>FY25Q4單季AR增加13.2%（+156.4百萬元），而營收僅增11.8%（+124.7百萬元）</li><li><strong>AR成長速度 &gt; 營收成長速度</strong>，這是「放帳衝業績」的典型特徵</li></ul><h3 id="二、ar-營收比背離測試-死亡交叉確認" tabindex="-1">二、AR/營收比背離測試：死亡交叉確認 <a class="header-anchor" href="#二、ar-營收比背離測試-死亡交叉確認" aria-label="Permalink to &quot;二、AR/營收比背離測試：死亡交叉確認&quot;">​</a></h3><table tabindex="0"><thead><tr><th>季度</th><th>AR QoQ%</th><th>Rev QoQ%</th><th>背離方向</th></tr></thead><tbody><tr><td>23Q2</td><td>+12.0%</td><td>-5.1%</td><td>AR升、營收降 → 警訊</td></tr><tr><td>23Q3</td><td>+14.1%</td><td>+42.7%</td><td>AR升、營收升 → 正常</td></tr><tr><td>24Q1</td><td>-0.5%</td><td>-20.3%</td><td>AR降、營收降 → 正常</td></tr><tr><td>24Q2</td><td>+5.9%</td><td>+21.8%</td><td>AR升、營收升 → 正常</td></tr><tr><td>24Q3</td><td>-13.1%</td><td>-15.6%</td><td>AR降、營收降 → 正常</td></tr><tr><td>24Q4</td><td>-0.2%</td><td>-3.9%</td><td>AR降、營收降 → 正常</td></tr><tr><td>25Q1</td><td>+1.4%</td><td>+7.4%</td><td>AR升、營收升 → 正常</td></tr><tr><td>25Q2</td><td>+1.5%</td><td>-3.9%</td><td>AR升、營收降 → 警訊</td></tr><tr><td>25Q3</td><td>+17.2%</td><td>+10.7%</td><td>AR升 &gt; 營收升 → 警訊</td></tr><tr><td>25Q4</td><td>+13.2%</td><td>+11.8%</td><td>AR升 &gt; 營收升 → 警訊</td></tr></tbody></table><p><strong>死亡交叉確認：</strong> FY25Q3-Q4連續兩季出現「AR QoQ &gt; Rev QoQ」的背離現象。這表示公司可能在（1）放寬信用政策以維持營收成長、或（2）客戶付款能力出現衰退。</p><h3 id="三、應收帳款結構分析-關係人集中度風險" tabindex="-1">三、應收帳款結構分析：關係人集中度風險 <a class="header-anchor" href="#三、應收帳款結構分析-關係人集中度風險" aria-label="Permalink to &quot;三、應收帳款結構分析：關係人集中度風險&quot;">​</a></h3><table tabindex="0"><thead><tr><th>季度</th><th>總AR(百萬元)</th><th>關係人AR(百萬元)</th><th>關係人佔比</th></tr></thead><tbody><tr><td>23Q1</td><td>839.3</td><td>92.9</td><td>11.1%</td></tr><tr><td>23Q2</td><td>939.8</td><td>92.6</td><td>9.9%</td></tr><tr><td>23Q3</td><td>1,071.9</td><td>93.2</td><td>8.7%</td></tr><tr><td>24Q1</td><td>1,066.3</td><td>92.7</td><td>8.7%</td></tr><tr><td>24Q2</td><td>1,128.9</td><td>96.1</td><td>8.5%</td></tr><tr><td>24Q3</td><td>981.5</td><td>99.2</td><td>10.1%</td></tr><tr><td>24Q4</td><td>979.3</td><td>96.0</td><td>9.8%</td></tr><tr><td>25Q1</td><td>993.1</td><td>95.7</td><td>9.6%</td></tr><tr><td>25Q2</td><td>1,008.0</td><td>97.5</td><td>9.7%</td></tr><tr><td>25Q3</td><td>1,181.8</td><td>95.9</td><td>8.1%</td></tr><tr><td>25Q4</td><td>1,338.2</td><td>95.2</td><td>7.1%</td></tr></tbody></table><p>關係人應收帳款佔比從8.5-11.1%區間逐步下降至7.1%，顯示非關係人客戶的AR快速增加。這可能反映：（1）公司依賴少數大客戶放帳、或（2）新客戶信用條件較寬鬆。</p><h3 id="四、壞帳準備金審查-是否適足" tabindex="-1">四、壞帳準備金審查：是否適足？ <a class="header-anchor" href="#四、壞帳準備金審查-是否適足" aria-label="Permalink to &quot;四、壞帳準備金審查：是否適足？&quot;">​</a></h3><p>根據FinMind數據，久元的應收帳款淨額已扣除呆帳準備。但由於缺乏詳細的帳齡分析數據（需查閱年報附註），無法精確評估壞帳準備金是否適足。</p><p><strong>間接判斷：</strong></p><ul><li>FY25Q4 DSO達101.8天，逾90天的AR佔比可能上升</li><li>若呆帳提列比例未隨DSO惡化而提高，則存在「調節損益」的激進會計手段風險</li><li>建議查閱FY25年報「財務報告附註→應收帳款帳齡分析」以確認</li></ul><h3 id="五、華爾街空頭視角-極端風險壓力測試" tabindex="-1">五、華爾街空頭視角：極端風險壓力測試 <a class="header-anchor" href="#五、華爾街空頭視角-極端風險壓力測試" aria-label="Permalink to &quot;五、華爾街空頭視角：極端風險壓力測試&quot;">​</a></h3><p><strong>情境一：客戶支付能力衰退</strong></p><ul><li>若主要客戶（如半導體大廠）面臨資本支出縮減，AR回收週期可能從102天拉長至130天以上</li><li>以FY25營收315.17億元計算，DSO每拉長10天將額外占用營運資金約8.6億元</li><li>久元期末現金及約當現金約26.4億元（FY24），雖可支撐，但將壓縮FCF</li></ul><p><strong>情境二：放帳衝業績的虛胖營收</strong></p><ul><li>FY25Q4 AR增加13.2%、營收僅增11.8%，差額1.4%可能來自信用放寬</li><li>若此趨勢延續至FY26，AR/營收比可能突破50%，DSO突破120天</li><li>屆時法人將重新評估久元的獲利含金量，估值可能下修</li></ul><p><strong>對策建議：</strong></p><ol><li>投資者應在FY26Q1（約2026年5月）密切關注DSO是否突破110天</li><li>若DSO連續兩季超過110天，應視為「放帳衝業績」的確認訊號</li><li>同時追蹤現金流表中的「應收帳款增加」項目，確認紙上獲利與實際現金流的差距</li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p>久元的應收帳款品質正在經歷結構性惡化。DSO從FY24的96天回升至FY25Q4的101.8天，且AR成長速度連續兩季超過營收成長速度——這是典型的「獲利品質虛胖」跡象。</p><p><strong>核心洞察：</strong> 久元的DSO惡化並非偶然事件，而是與應收帳款佔營收比重上升（24.7%→42.5%）同步發生的結構性趨勢。這可能反映：（1）半導體測試設備業的競爭加劇導致公司必須提供更長的信用期以爭取訂單、或（2）主要客戶的議價能力增強，要求更長的付款週期。</p><p><strong>正面因素：</strong></p><ol><li>DSO雖惡化但仍維持在102天以內，未突破120天的危險水位</li><li>關係人AR佔比持續下降（7.1%），顯示非關係人客戶結構改善</li><li>FY25全年CFO/NI比率仍達266.4%，顯示整體現金流品質未受嚴重影響</li></ol><p><strong>負面警訊：</strong></p><ol><li>DSO連續兩季突破100天大關（FY25Q3: 100.5天、Q4: 101.8天）</li><li>AR成長速度（+13.2% QoQ in Q4）持續快於營收成長速度（+11.8% QoQ）</li><li>應收帳款佔營收比重從FY24的26.6%上升至FY25的42.5%，上升15.9個百分點</li><li>FY25Q2出現「AR升(+1.5%)、營收降(-3.9%)」的死亡交叉</li></ol><p><strong>綜合判斷：</strong> 久元的應收帳款品質目前處於「持平偏警訊」狀態。DSO尚未突破120天的危險水位，但惡化趨勢已確認。投資者應將DSO視為核心監控指標——若FY26Q1的DSO突破110天，將確認「放帳衝業績」的論述，對投資評等構成負面影響。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py balance_sheet 6261 2023-04-01 2026-04-24 --df</code>（科目：應收帳款淨額、應收帳款－關係人淨額）</li><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py finance 6261 2023-04-01 2026-04-24 --df</code>（科目：營業收入）</li><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py cash_flow 6261 2023-04-01 2026-04-24 --df</code>（科目：應收帳款增加/減少）</li><li><strong>數據採集器查詢</strong>: <code>python3 /Users/kaipro/.openclaw/skills/finmind/數據採集器.py revenue 6261 2023-04-01 2026-04-24 --df</code>（科目：月營收）</li><li><strong>富果法說會摘要</strong>: <a href="https://blog.fugle.tw/post/earnings-call-6261-2025-08-28%EF%BC%88%E4%B8%8A%E5%8D%8A%E5%B9%B4%E7%87%9F%E6%94%B619.5%E5%84%84%E5%85%83%E3%80%81%E6%AF%9B%E5%88%A9%E7%8E%8728%25%EF%BC%89" target="_blank" rel="noreferrer">https://blog.fugle.tw/post/earnings-call-6261-2025-08-28（上半年營收19.5億元、毛利率28%）</a></li></ul>',45)])])}const F=d(o,[["render",e]]);export{c as __pageData,F as default};
